package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController enforces per-namespace limits on the number of
// CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
	logger                logrus.FieldLogger
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	maxPerNamespace       int

	// policyCountMutex protects policyCount
	policyCountMutex sync.RWMutex
	// policyCount stores the count of CiliumNetworkPolicy resources per namespace
	policyCount map[string]int
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	logger logrus.FieldLogger,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	if logger == nil {
		logger = log
	}
	return &PolicyQuotaController{
		logger:                logger,
		ciliumNetworkPolicies: ciliumNetworkPolicies,
		maxPerNamespace:       maxPerNamespace,
		policyCount:           make(map[string]int),
	}
}

// Run implements the controller loop. It watches CiliumNetworkPolicy resources
// and maintains per-namespace counts.
func (pc *PolicyQuotaController) Run(ctx context.Context) error {
	cnpEvents := pc.ciliumNetworkPolicies.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case event, ok := <-cnpEvents:
			if !ok {
				return nil
			}

			var err error
			switch event.Kind {
			case resource.Upsert:
				err = pc.onPolicyUpsert(event.Object)
			case resource.Delete:
				err = pc.onPolicyDelete(event.Object)
			case resource.Sync:
				pc.logger.Debug("CiliumNetworkPolicy resources synchronized")
			}

			event.Done(err)
		}
	}
}

// onPolicyUpsert handles upsert events for CiliumNetworkPolicy resources.
func (pc *PolicyQuotaController) onPolicyUpsert(policy *cilium_v2.CiliumNetworkPolicy) error {
	if policy == nil {
		return nil
	}

	namespace := policy.Namespace
	if namespace == "" {
		namespace = "default"
	}

	pc.policyCountMutex.Lock()
	pc.policyCount[namespace]++
	pc.policyCountMutex.Unlock()

	pc.logger.WithFields(logrus.Fields{
		"namespace": namespace,
		"name":      policy.Name,
		"count":     pc.policyCount[namespace],
	}).Debug("CiliumNetworkPolicy created/updated")

	return nil
}

// onPolicyDelete handles delete events for CiliumNetworkPolicy resources.
func (pc *PolicyQuotaController) onPolicyDelete(policy *cilium_v2.CiliumNetworkPolicy) error {
	if policy == nil {
		return nil
	}

	namespace := policy.Namespace
	if namespace == "" {
		namespace = "default"
	}

	pc.policyCountMutex.Lock()
	if pc.policyCount[namespace] > 0 {
		pc.policyCount[namespace]--
	}
	if pc.policyCount[namespace] == 0 {
		delete(pc.policyCount, namespace)
	}
	pc.policyCountMutex.Unlock()

	pc.logger.WithFields(logrus.Fields{
		"namespace": namespace,
		"name":      policy.Name,
	}).Debug("CiliumNetworkPolicy deleted")

	return nil
}

// CheckQuota returns an error if the quota for the given namespace would be exceeded
// by adding one more policy.
func (pc *PolicyQuotaController) CheckQuota(namespace string) error {
	if namespace == "" {
		namespace = "default"
	}

	pc.policyCountMutex.RLock()
	currentCount := pc.policyCount[namespace]
	pc.policyCountMutex.RUnlock()

	if pc.maxPerNamespace > 0 && currentCount >= pc.maxPerNamespace {
		return fmt.Errorf(
			"policy quota exceeded in namespace %s: %d/%d policies",
			namespace, currentCount, pc.maxPerNamespace,
		)
	}

	return nil
}

// GetNamespaceCount returns the current count of policies in the given namespace.
func (pc *PolicyQuotaController) GetNamespaceCount(namespace string) int {
	if namespace == "" {
		namespace = "default"
	}

	pc.policyCountMutex.RLock()
	defer pc.policyCountMutex.RUnlock()
	return pc.policyCount[namespace]
}

